import type { RendererRunEvent, RunStatus } from "@shared/types";

export type AgentProgressStatus = RunStatus;

export type AgentProgressMetrics = {
  elapsedMs: number | null;
  elapsedLabel: string;
  filesEdited: number | null;
  webSearches: number | null;
  totalEvents: number;
  startedAt: string | null;
  endedAt: string | null;
  lastEventAt: string | null;
  statusLabel: string;
  statusDetail: string;
  statusTone: "idle" | "active" | "success" | "warning" | "danger";
  active: boolean;
  metricsAvailable: boolean;
};

export type AgentProgressInput = {
  events: RendererRunEvent[];
  status: AgentProgressStatus;
  startedAt?: string | null;
  endedAt?: string | null;
  now?: number;
  metricsAvailable?: boolean;
};

const pad2 = (value: number): string => String(value).padStart(2, "0");

const timestampMs = (timestamp?: string | null): number | null => {
  if (!timestamp) return null;
  const parsed = Date.parse(timestamp);
  return Number.isNaN(parsed) ? null : parsed;
};

const eventTime = (event: RendererRunEvent): number => timestampMs(event.timestamp) ?? 0;

export const isAgentSessionActive = (status: AgentProgressStatus): boolean =>
  status === "queued" || status === "running" || status === "drafting";

export const formatElapsedDuration = (durationMs: number | null): string => {
  if (durationMs === null) return "Unavailable";
  const totalSeconds = Math.max(0, Math.floor(durationMs / 1000));
  const seconds = totalSeconds % 60;
  const totalMinutes = Math.floor(totalSeconds / 60);
  const minutes = totalMinutes % 60;
  const hours = Math.floor(totalMinutes / 60);
  return hours > 0 ? `${hours}:${pad2(minutes)}:${pad2(seconds)}` : `${pad2(minutes)}:${pad2(seconds)}`;
};

export const isWebSearchEvent = (event: RendererRunEvent): boolean =>
  event.type === "web.search" || (event.type === "agent.message.delta" && /^web search:/i.test(event.text.trim()));

export const agentEventText = (event: RendererRunEvent): string => {
  switch (event.type) {
    case "run.started":
      return `Run started (${event.threadId})`;
    case "agent.message.delta":
    case "agent.message.completed":
      return event.text;
    case "command.started":
      return `$ ${event.command}`;
    case "command.output":
      return event.text;
    case "command.completed":
      return `Command ${event.status}`;
    case "file.change":
      return event.summary ?? event.path;
    case "web.search":
      return `Web search: ${event.query}`;
    case "approval.requested":
      return `Approval requested: ${event.kind}`;
    case "approval.resolved":
      return `Approval ${event.decision}`;
    case "ticket.status_changed":
      return `Status moved from ${event.fromStatus} to ${event.toStatus}`;
    case "clarification.requested":
      return `${event.questions.length} clarification question${event.questions.length === 1 ? "" : "s"} requested`;
    case "run.completed":
      return event.finalResponse;
    case "run.failed":
      return event.message;
    default:
      return "";
  }
};

export const isMarkdownAgentEvent = (event: RendererRunEvent): boolean =>
  event.type === "agent.message.completed" || event.type === "run.completed";

export const agentEventLabel = (event: RendererRunEvent): string => {
  switch (event.type) {
    case "run.started":
    case "run.completed":
    case "run.failed":
      return "Run";
    case "agent.message.delta":
    case "agent.message.completed":
      return isWebSearchEvent(event) ? "Web Search" : "Message";
    case "command.started":
    case "command.output":
    case "command.completed":
      return "Command";
    case "file.change":
      return "File";
    case "web.search":
      return "Web Search";
    case "approval.requested":
    case "approval.resolved":
      return "Approval";
    case "ticket.status_changed":
      return "Status";
    case "clarification.requested":
      return "Clarification";
    default:
      return "Event";
  }
};

export const agentEventTone = (event: RendererRunEvent): "neutral" | "success" | "warning" | "danger" | "info" => {
  if (event.type === "run.failed" || (event.type === "command.completed" && event.status === "failed")) return "danger";
  if (event.type === "run.completed" || (event.type === "command.completed" && event.status === "completed")) return "success";
  if (event.type === "clarification.requested" || event.type === "approval.requested") return "warning";
  if (isWebSearchEvent(event) || event.type === "file.change" || event.type === "ticket.status_changed") return "info";
  return "neutral";
};

export const sortAgentEvents = (events: RendererRunEvent[]): RendererRunEvent[] =>
  events
    .map((event, index) => ({ event, index }))
    .sort((a, b) => eventTime(a.event) - eventTime(b.event) || a.index - b.index)
    .map(({ event }) => event);

export const mergeRunEvents = (...eventGroups: RendererRunEvent[][]): RendererRunEvent[] => {
  const merged = new Map<string, RendererRunEvent>();
  for (const event of eventGroups.flat()) {
    const key = `${event.runId}|${event.timestamp}|${event.type}|${agentEventText(event)}`;
    if (!merged.has(key)) merged.set(key, event);
  }
  return sortAgentEvents([...merged.values()]);
};

const statusCopy = (
  status: AgentProgressStatus
): Pick<AgentProgressMetrics, "statusLabel" | "statusDetail" | "statusTone"> => {
  switch (status) {
    case "queued":
      return { statusLabel: "Queued", statusDetail: "Codex is waiting to start this ticket.", statusTone: "active" };
    case "drafting":
      return { statusLabel: "Drafting", statusDetail: "Codex is preparing a ticket draft.", statusTone: "active" };
    case "draft_failed":
      return { statusLabel: "Draft failed", statusDetail: "The ticket draft run ended with an error.", statusTone: "danger" };
    case "draft_complete":
      return { statusLabel: "Draft ready", statusDetail: "The generated ticket draft is ready.", statusTone: "success" };
    case "running":
      return { statusLabel: "Active", statusDetail: "Codex is working on this ticket.", statusTone: "active" };
    case "blocked":
      return { statusLabel: "Needs input", statusDetail: "Codex is waiting on clarification.", statusTone: "warning" };
    case "failed":
      return { statusLabel: "Failed", statusDetail: "The agent session ended with an error.", statusTone: "danger" };
    case "completed":
      return { statusLabel: "Completed", statusDetail: "The latest agent session has finished.", statusTone: "success" };
    case "cancelled":
      return { statusLabel: "Cancelled", statusDetail: "The latest agent session was stopped.", statusTone: "danger" };
    case "idle":
    default:
      return { statusLabel: "Inactive", statusDetail: "No agent session is currently active.", statusTone: "idle" };
  }
};

export const deriveAgentProgress = ({
  events,
  status,
  startedAt,
  endedAt,
  now = Date.now(),
  metricsAvailable
}: AgentProgressInput): AgentProgressMetrics => {
import test from "node:test";
import assert from "node:assert/strict";
import { renderToStaticMarkup } from "react-dom/server";
import { AgentActivityPanel, AgentLogViewer, AgentProgressSummary } from "../src/renderer/src/components/AgentActivity";
import { deriveAgentProgress, formatElapsedDuration } from "../src/renderer/src/lib/agentProgress";
import type { RendererRunEvent } from "../src/shared/types";

const baseEvent = {
  projectPath: "/tmp/relay-project",
  ticketId: "tkt_1",
  runId: "run_1"
};

const event = (patch: Partial<RendererRunEvent> & { type: RendererRunEvent["type"]; timestamp: string }): RendererRunEvent =>
  ({
    ...baseEvent,
    ...patch
  }) as RendererRunEvent;

test("agent progress derives elapsed time and count metrics from run events", () => {
  const events: RendererRunEvent[] = [
    event({ type: "run.started", runId: "run_1", threadId: "thread_1", timestamp: "2026-05-11T10:00:00.000Z" }),
    event({ type: "file.change", path: "src/App.tsx", summary: "update src/App.tsx", timestamp: "2026-05-11T10:00:20.000Z" }),
    event({ type: "file.change", path: "src/App.tsx", summary: "update src/App.tsx", timestamp: "2026-05-11T10:00:30.000Z" }),
    event({ type: "web.search", query: "Codex SDK event types", timestamp: "2026-05-11T10:00:40.000Z" }),
    event({ type: "agent.message.delta", text: "Web search: legacy query", timestamp: "2026-05-11T10:00:45.000Z" }),
    event({ type: "run.completed", finalResponse: "Done.", timestamp: "2026-05-11T10:01:05.000Z" })
  ];

  const progress = deriveAgentProgress({ events, status: "completed", now: Date.parse("2026-05-11T10:02:00.000Z") });

  assert.equal(progress.elapsedLabel, "01:05");
  assert.equal(progress.filesEdited, 1);
  assert.equal(progress.webSearches, 2);
  assert.equal(progress.statusLabel, "Completed");
});

test("elapsed duration formatting stays stable across minute and hour boundaries", () => {
  assert.equal(formatElapsedDuration(null), "Unavailable");
  assert.equal(formatElapsedDuration(0), "00:00");
  assert.equal(formatElapsedDuration(61_000), "01:01");
  assert.equal(formatElapsedDuration(3_661_000), "1:01:01");
});

test("agent progress summary renders active elapsed state and unavailable metrics", () => {
  const markup = renderToStaticMarkup(
    <AgentProgressSummary
      events={[]}
      status="drafting"
      startedAt="2026-05-11T10:00:00.000Z"
      metricsAvailable={false}
      now={Date.parse("2026-05-11T10:01:01.000Z")}
    />
  );

  assert.match(markup, /Drafting/);
  assert.match(markup, /01:01/);
  assert.match(markup, /Files Edited/);
  assert.match(markup, /Unavailable/);
});

test("agent activity panel exposes a dedicated log entry point", () => {
  const markup = renderToStaticMarkup(
    <AgentActivityPanel
      events={[
        event({ type: "run.started", runId: "run_1", threadId: "thread_1", timestamp: "2026-05-11T10:00:00.000Z" })
      ]}
      status="running"
      runId="run_1"
      runSummary={null}
      logLoading={false}
      logError={null}
      onOpenLogs={() => undefined}
      onRevealFile={() => undefined}
    />
  );

  assert.match(markup, /Agent Activity/);
  assert.match(markup, /Open Logs/);
  assert.match(markup, /Recent Activity/);
});

test("agent activity panel renders run summary timing and token usage", () => {
  const markup = renderToStaticMarkup(
    <AgentActivityPanel
      events={[
        event({ type: "run.started", runId: "run_1", threadId: "thread_1", timestamp: "2026-05-11T10:00:00.000Z" }),
        event({ type: "run.completed", finalResponse: "Done.", timestamp: "2026-05-11T10:01:05.000Z" })
      ]}
      status="completed"
      runId="run_1"
      runSummary={{
        schemaVersion: 1,
        ticketId: "tkt_1",
        runId: "run_1",
        threadId: "thread_1",
        startedAt: "2026-05-11T10:00:00.000Z",
        endedAt: "2026-05-11T10:01:05.000Z",
        durationMs: 65_000,
        finalStatus: "completed",
        usage: {
          inputTokens: 1200,
          cachedInputTokens: 400,
          outputTokens: 300,
          reasoningOutputTokens: 50,
          totalTokens: 1500
        },
        eventCount: 2,
        latestEventAt: "2026-05-11T10:01:05.000Z"
      }}
      logLoading={false}
      logError={null}
      onOpenLogs={() => undefined}
      onRevealFile={() => undefined}
    />
  );

  assert.match(markup, /Latest run summary/);
  assert.match(markup, /Duration/);
  assert.match(markup, /01:05/);
  assert.match(markup, /Token Usage/);
  assert.match(markup, /1,500/);
});

test("agent activity panel marks token usage unavailable when absent", () => {
  const markup = renderToStaticMarkup(
    <AgentActivityPanel
      events={[event({ type: "run.failed", message: "The operation was aborted.", timestamp: "2026-05-11T10:00:30.000Z" })]}
      status="cancelled"
      runId="run_1"
      runSummary={{
        schemaVersion: 1,
        ticketId: "tkt_1",
        runId: "run_1",
        threadId: "thread_1",
        startedAt: "2026-05-11T10:00:00.000Z",
        endedAt: "2026-05-11T10:00:30.000Z",
        durationMs: 30_000,
        finalStatus: "cancelled",
        usage: null,
        eventCount: 1,
        latestEventAt: "2026-05-11T10:00:30.000Z"
      }}
      logLoading={false}
      logError={null}
      onOpenLogs={() => undefined}
      onRevealFile={() => undefined}
    />
  );

  assert.match(markup, /Cancelled/);
  assert.match(markup, /Token Usage/);
  assert.match(markup, /Unavailable from this run log/);
});

test("agent log viewer orders events chronologically and labels event types", () => {
  const markup = renderToStaticMarkup(
    <AgentLogViewer
      title="Ticket Logs"
      loading={false}
      error={null}
      events={[
        event({ type: "command.started", command: "npm test", timestamp: "2026-05-11T10:00:30.000Z" }),
        event({ type: "web.search", query: "Relay docs", timestamp: "2026-05-11T10:00:20.000Z" }),
        event({ type: "run.started", runId: "run_1", threadId: "thread_1", timestamp: "2026-05-11T10:00:10.000Z" })
      ]}
      onClose={() => undefined}
    />
  );

  assert.ok(markup.indexOf("run.started") < markup.indexOf("web.search"));
  assert.ok(markup.indexOf("web.search") < markup.indexOf("command.started"));
  assert.match(markup, /Run/);
  assert.match(markup, /Web Search/);
  assert.match(markup, /Command/);
});

test("agent log viewer distinguishes loading, failed, and empty states", () => {
  const loadingMarkup = renderToStaticMarkup(
    <AgentLogViewer title="Ticket Logs" loading events={[]} error={null} onClose={() => undefined} />
  );
  const errorMarkup = renderToStaticMarkup(
    <AgentLogViewer title="Ticket Logs" loading={false} events={[]} error="Missing log file" onClose={() => undefined} />
  );
  const emptyMarkup = renderToStaticMarkup(
    <AgentLogViewer title="Ticket Logs" loading={false} events={[]} error={null} onClose={() => undefined} />
  );

  assert.match(loadingMarkup, /Loading saved log events/);
  assert.match(errorMarkup, /Unable to load saved log events: Missing log file/);
  assert.match(emptyMarkup, /No detailed log events are available/);
});
import test from "node:test";
import assert from "node:assert/strict";
import { summarizeRunLogLines, summarizeRunUsage } from "../src/main/services/run-events";
import type { RunLogLine } from "../src/shared/types";

const baseLine = (patch: Partial<RunLogLine> & Pick<RunLogLine, "timestamp" | "type" | "payload">): RunLogLine => ({
  schemaVersion: 1,
  ticketId: "tkt_1",
  runId: "run_1",
  threadId: "thread_1",
  ...patch
});

test("run summaries derive timing, status, thread, and token usage from JSONL events", () => {
  const lines: RunLogLine[] = [
    baseLine({
      timestamp: "2026-05-11T10:00:00.000Z",
      type: "run.started",
      payload: { runId: "run_1", threadId: "thread_1" }
    }),
    baseLine({
      timestamp: "2026-05-11T10:01:05.000Z",
      type: "run.completed",
      payload: {
        finalResponse: "Done.",
        usage: {
          input_tokens: 120,
          cached_input_tokens: 40,
          output_tokens: 30,
          reasoning_output_tokens: 5,
          total_tokens: 150
        }
      }
    })
  ];

  const summary = summarizeRunLogLines("tkt_1", "run_1", lines);

  assert.equal(summary?.threadId, "thread_1");
  assert.equal(summary?.startedAt, "2026-05-11T10:00:00.000Z");
  assert.equal(summary?.endedAt, "2026-05-11T10:01:05.000Z");
  assert.equal(summary?.durationMs, 65_000);
  assert.equal(summary?.finalStatus, "completed");
  assert.deepEqual(summary?.usage, {
    inputTokens: 120,
    cachedInputTokens: 40,
    outputTokens: 30,
    reasoningOutputTokens: 5,
    totalTokens: 150
  });
});

test("run summaries remain readable for usage-absent cancelled logs", () => {
  const lines: RunLogLine[] = [
    baseLine({
      timestamp: "2026-05-11T10:00:00.000Z",
      type: "run.started",
      payload: { runId: "run_1", threadId: "thread_1" }
    }),
    baseLine({
      timestamp: "2026-05-11T10:00:30.000Z",
      type: "run.failed",
      payload: { message: "The operation was aborted." }
    })
  ];

  const summary = summarizeRunLogLines("tkt_1", "run_1", lines);

  assert.equal(summary?.finalStatus, "cancelled");
  assert.equal(summary?.durationMs, 30_000);
  assert.equal(summary?.usage, null);
});

test("run summaries infer failed status for legacy failure logs", () => {
  const lines: RunLogLine[] = [
    baseLine({
      timestamp: "2026-05-11T10:00:00.000Z",
      type: "run.started",
      payload: { runId: "run_1", threadId: "thread_1" }
    }),
    baseLine({
      timestamp: "2026-05-11T10:00:45.000Z",
      type: "run.failed",
      payload: { message: "SDK stream failed." }
    })
  ];

  const summary = summarizeRunLogLines("tkt_1", "run_1", lines);

  assert.equal(summary?.finalStatus, "failed");
  assert.equal(summary?.endedAt, "2026-05-11T10:00:45.000Z");
  assert.equal(summary?.durationMs, 45_000);
});


test("usage summary accepts nested token detail shapes and computes totals when needed", () => {
  assert.deepEqual(
    summarizeRunUsage({
      inputTokens: 10,
      outputTokens: 5,
      inputTokenDetails: { cachedTokens: 2 },
      outputTokenDetails: { reasoningTokens: 3 }
    }),
    {
      inputTokens: 10,
      cachedInputTokens: 2,
      outputTokens: 5,
      reasoningOutputTokens: 3,
      totalTokens: 15
    }
  );
  assert.equal(summarizeRunUsage(undefined), null);
  assert.equal(summarizeRunUsage({ request_id: "not-token-usage" }), null);
});

  answer: string;
