export type RelayAuditEvent = {
  schemaVersion: number;
  timestamp: string;
  actor: RelayActor;
  source: RelayEventSource;
  eventType: "ticket.status_changed" | "clarification.question_created" | "clarification.answer_submitted";
  ticketId?: string;
  runId?: string | null;
  payload: Record<string, unknown>;
};

export type AddProjectResult = {
  project: ProjectSummary;
  initialized: boolean;
};

export type AppRegistry = {
  schemaVersion: number;
  projects: Array<{
    path: string;
    pinned: boolean;
    lastOpenedAt: string;
    sidebarPosition: number;
  }>;
  ui: {
    lastProjectPath: string | null;
    theme: ThemePreference;
  };
};

export type RelayCodexEvent =
  | { type: "run.started"; runId: string; threadId: string; timestamp: string }
  | { type: "agent.message.delta"; text: string; timestamp: string }
  | { type: "agent.message.completed"; text: string; timestamp: string }
  | { type: "command.started"; command: string; cwd?: string; timestamp: string }
  | { type: "command.output"; stream: "stdout" | "stderr"; text: string; timestamp: string }
  | { type: "command.completed"; status: "completed" | "failed" | "declined"; timestamp: string }
  | { type: "file.change"; path: string; summary?: string; timestamp: string }
  | { type: "web.search"; query: string; timestamp: string }
  | { type: "approval.requested"; approvalId: string; kind: "command" | "file-change" | "network" | "other"; payload: unknown; timestamp: string }
  | { type: "approval.resolved"; approvalId: string; decision: string; timestamp: string }
  | { type: "ticket.status_changed"; fromStatus: string; toStatus: string; actor: RelayActor; source: RelayEventSource; timestamp: string }
  | { type: "clarification.requested"; questions: ClarificationQuestion[]; timestamp: string }
  | { type: "run.completed"; finalResponse: string; usage?: unknown; finalStatus?: RunStatus; timestamp: string }
  | { type: "run.failed"; message: string; details?: unknown; finalStatus?: RunStatus; timestamp: string };

export type RendererRunEvent = RelayCodexEvent & {
  projectPath: string;
  ticketId: string;
  runId: string;
};

export type RelayApprovalDecision = "accept" | "acceptForSession" | "decline" | "cancel";

export type CodexStatus = {
  sdkAvailable: boolean;
  cliAvailable: boolean;
  cliVersion: string | null;
  authenticated: boolean | null;
  message: string;
};

export type StartRunInput = {
  projectPath: string;
  ticketId: string;
  freshThread?: boolean;
};

export const clarificationAnswerInputSchema: RelaySchema<ClarificationAnswerInput> = passthroughStruct({
  projectPath: Schema.String,
  ticketId: Schema.String,
  questionId: Schema.String,
  answer: Schema.String
});

export const createDraftInputSchema: RelaySchema<CreateDraftInput> = passthroughStruct({
  projectPath: Schema.String,
  idea: Schema.String,
  preferredTicketType: Schema.optional(ticketTypeSchema),
  ticketId: Schema.optional(Schema.String)
});

export const startRunInputSchema: RelaySchema<StartRunInput> = passthroughStruct({
  projectPath: Schema.String,
  ticketId: Schema.String,
  freshThread: Schema.optional(Schema.Boolean)
});

export const agentTicketUpdateInputSchema: RelaySchema<AgentTicketUpdateInput> = passthroughStruct({
  projectPath: Schema.String,
  ticketId: Schema.String,
  request: Schema.String
});

export const relayApprovalDecisionSchema: RelaySchema<RelayApprovalDecision> = Schema.Literals([
  "accept",
  "acceptForSession",
  "decline",
  "cancel"
]);

const relayCodexEventTypeSchema: RelaySchema<RelayCodexEvent["type"]> = Schema.Literals([
  "run.started",
  "agent.message.delta",
  "agent.message.completed",
  "command.started",
  "command.output",
  "command.completed",
  "file.change",
  "web.search",
  "approval.requested",
  "approval.resolved",
  "ticket.status_changed",
  "clarification.requested",
  "run.completed",
  "run.failed"
]);

export const relayCodexEventSchema: RelaySchema<RelayCodexEvent> = Schema.Union([
  Schema.Struct({ type: Schema.Literal("run.started"), runId: Schema.String, threadId: Schema.String, timestamp: isoString }),
  Schema.Struct({ type: Schema.Literal("agent.message.delta"), text: Schema.String, timestamp: isoString }),
  Schema.Struct({ type: Schema.Literal("agent.message.completed"), text: Schema.String, timestamp: isoString }),
  Schema.Struct({ type: Schema.Literal("command.started"), command: Schema.String, cwd: Schema.optional(Schema.String), timestamp: isoString }),
  Schema.Struct({
    type: Schema.Literal("command.output"),
    stream: Schema.Literals(["stdout", "stderr"]),
    text: Schema.String,
    timestamp: isoString
  }),
  Schema.Struct({
    type: Schema.Literal("command.completed"),
    status: Schema.Literals(["completed", "failed", "declined"]),
    timestamp: isoString
  }),
  Schema.Struct({ type: Schema.Literal("file.change"), path: Schema.String, summary: Schema.optional(Schema.String), timestamp: isoString }),
  Schema.Struct({ type: Schema.Literal("web.search"), query: Schema.String, timestamp: isoString }),
  Schema.Struct({
    type: Schema.Literal("approval.requested"),
    approvalId: Schema.String,
    kind: Schema.Literals(["command", "file-change", "network", "other"]),
    payload: unknownRecordSchema,
    timestamp: isoString
  }),
  Schema.Struct({ type: Schema.Literal("approval.resolved"), approvalId: Schema.String, decision: Schema.String, timestamp: isoString }),
  Schema.Struct({
    type: Schema.Literal("ticket.status_changed"),
    fromStatus: Schema.String,
    toStatus: Schema.String,
    actor: relayActorSchema,
    source: relayEventSourceSchema,
    timestamp: isoString
  }),
  Schema.Struct({
    type: Schema.Literal("clarification.requested"),
    questions: mutableArray(clarificationQuestionSchema),
    timestamp: isoString
  }),
  Schema.Struct({
    type: Schema.Literal("run.completed"),
    finalResponse: Schema.String,
    usage: Schema.optional(Schema.Unknown),
    finalStatus: Schema.optional(runStatusSchema),
    timestamp: isoString
  }),
  Schema.Struct({
    type: Schema.Literal("run.failed"),
    message: Schema.String,
    details: Schema.optional(Schema.Unknown),
    finalStatus: Schema.optional(runStatusSchema),
    timestamp: isoString
  })
]);

export const runLogLineSchema: RelaySchema<RunLogLine> = Schema.Struct({
  schemaVersion: numberSchema,
  timestamp: isoString,
  ticketId: Schema.String,
  runId: Schema.String,
  threadId: Schema.String,

  activeRuns.set(runId, {
    abortController,
    ticketId,
    projectPath
  });

  const draftDependencies: TicketDraftStartDependencies = {
    ...dependencies,
