  assert.equal("settingsExtra" in (config.settings as object), false);

  assert.throws(
    () =>
      parseSchema(agentTicketUpdateSchema, {
        title: "Strict update",
        priority: "high",
        labels: [],
        markdown: "Updated markdown.",
        clarificationQuestions: [],
        extra: "rejected"
      }),
