  );

  const explicitConcurrency = parseSchema(projectConfigSchema, {
    ...config,
    settings: {
      ...config.settings,
      agentConcurrency: 2
    }
  });
  assert.equal(explicitConcurrency.settings.agentConcurrency, 2);

  assert.throws(
    () =>
      parseSchema(projectConfigSchema, {
        ...config,
        settings: {
          ...config.settings,
          agentConcurrency: 0
