888	  assert.equal(completedMcp.server, "github");
889	  assert.equal(completedMcp.tool, "search");
890	  assert.equal("arguments" in completedMcp, false);

 50	  return hours > 0 ? `${hours}:${pad2(minutes)}:${pad2(seconds)}` : `${pad2(minutes)}:${pad2(seconds)}`;
