 53	export const isWebSearchEvent = (event: RendererRunEvent): boolean =>
 54	  event.type === "web.search" || (event.type === "agent.message.delta" && /^web search:/i.test(event.text.trim()));
 55	
 56	const formatMcpStatus = (status: "in_progress" | "completed" | "failed"): string => status.replace("_", " ");
 57	
 58	export const agentEventText = (event: RendererRunEvent): string => {
 59	  switch (event.type) {
 60	    case "run.started":
 61	      return `Run started (${event.threadId})`;
 62	    case "agent.message.delta":
 63	    case "agent.message.completed":
 64	      return event.text;
 65	    case "command.started":
 66	      return `$ ${event.command}`;
 67	    case "command.output":
 68	      return event.text;
 69	    case "command.completed":
 70	      return `Command ${event.status}`;
 71	    case "file.change":
 72	      return event.summary ?? event.path;
 73	    case "web.search":
 74	      return `Web search: ${event.query}`;
 75	    case "todo.updated": {
 76	      const completed = event.items.filter((item) => item.completed).length;
 77	      const summary =
 78	        event.items.length === 0
 79	          ? "Todo list updated: no items"
 80	          : `Todo list updated: ${completed}/${event.items.length} completed`;
 81	      const items = event.items.map((item) => `[${item.completed ? "x" : " "}] ${item.text}`).join("\n");
 82	      return items ? `${summary}\n${items}` : summary;
 83	    }
 84	    case "mcp.tool_call": {
 85	      const call = `${event.server}.${event.tool}`;
 86	      const status = formatMcpStatus(event.status);
 87	      return event.error ? `MCP tool ${status}: ${call}: ${event.error}` : `MCP tool ${status}: ${call}`;
 88	    }
 89	    case "approval.requested":
 90	      return `Approval requested: ${event.kind}`;
 91	    case "approval.resolved":
 92	      return `Approval ${event.decision}`;
 93	    case "ticket.status_changed":
 94	      return `Status moved from ${event.fromStatus} to ${event.toStatus}`;
 95	    case "clarification.requested":
 96	      return `${event.questions.length} clarification question${event.questions.length === 1 ? "" : "s"} requested`;
 97	    case "run.completed":
 98	      return event.finalResponse;
 99	    case "run.failed":
100	      return event.message;
101	    default:
102	      return "";
103	  }
104	};
