109	export const agentEventLabel = (event: RendererRunEvent): string => {
110	  switch (event.type) {
111	    case "run.started":
112	    case "run.completed":
113	    case "run.failed":
114	      return "Run";
115	    case "agent.message.delta":
116	    case "agent.message.completed":
117	      return isWebSearchEvent(event) ? "Web Search" : "Message";
118	    case "command.started":
119	    case "command.output":
120	    case "command.completed":
121	      return "Command";
122	    case "file.change":
123	      return "File";
124	    case "web.search":
125	      return "Web Search";
126	    case "todo.updated":
127	      return "Todo";
128	    case "mcp.tool_call":
129	      return "MCP Tool";
130	    case "approval.requested":
131	    case "approval.resolved":
132	      return "Approval";
133	    case "ticket.status_changed":
134	      return "Status";
135	    case "clarification.requested":
136	      return "Clarification";
137	    default:
138	      return "Event";
139	  }
